            } while (e_STARTED != d_threadStartState
                  || e_RESUMED != d_threadSuspendState);
        }  // release mutex

        {
            ThreadFunctor job;

            // Retrieve the next job, blocking until one is available.
            d_queue.popFront(&job);

            if (job) {
                // Run the job.
                ++d_numActiveThreads;
                job();                                                // INVOKE
                --d_numActiveThreads;
            }
        }
    }
}

